-- Kisah lengkap 25 nabi — bab-bab kisah penuh untuk setiap profil nabi di
-- kisah_person (owner: "kisah para nabi harusnya full seluruh kisahnya").
-- Narasi mengikuti alur Al-Qur'an dengan kerangka Qashash al-Anbiya (Ibnu
-- Katsir); setiap bab mencantumkan rujukan ayat/hadits sandarannya di kolom
-- quran_refs. Idempoten: INSERT OR IGNORE + UNIQUE(person_slug, section_order).
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('adam', 1, 'Penciptaan dan Kemuliaan Adam', 'Allah mengabarkan kepada para malaikat bahwa Dia akan menjadikan seorang khalifah di muka bumi. Para malaikat bertanya mengapa Allah menjadikan makhluk yang akan berbuat kerusakan dan menumpahkan darah, padahal mereka senantiasa bertasbih memuji-Nya. Allah menjawab, "Sesungguhnya Aku mengetahui apa yang tidak kamu ketahui." Adam diciptakan dari tanah, lalu Allah meniupkan ruh kepadanya dan mengajarkan kepadanya nama-nama seluruh benda — ilmu yang tidak dimiliki para malaikat. Ketika para malaikat tidak mampu menyebutkan nama-nama itu, Adam menyebutkannya, dan tampaklah kemuliaan ilmu yang Allah karuniakan kepada manusia.', 'QS Al-Baqarah: 30–33 · QS Shad: 71–72 · QS Al-Hijr: 28–29');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('adam', 2, 'Sujud Para Malaikat dan Pembangkangan Iblis', 'Allah memerintahkan seluruh malaikat bersujud kepada Adam sebagai penghormatan, bukan penyembahan. Semua bersujud kecuali Iblis. Ia menyombongkan diri dan berkata, "Aku lebih baik daripadanya; Engkau ciptakan aku dari api sedangkan dia Engkau ciptakan dari tanah." Karena kesombongan itu Iblis diusir dari rahmat Allah, lalu ia meminta penangguhan hingga hari kiamat dan bersumpah akan menyesatkan anak keturunan Adam dari segala arah — kecuali hamba-hamba Allah yang ikhlas.', 'QS Al-Baqarah: 34 · QS Al-A''raf: 11–18 · QS Shad: 73–83');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('adam', 3, 'Tinggal di Surga dan Tergelincir oleh Godaan', 'Adam dan istrinya, Hawa, ditempatkan di surga dan dipersilakan menikmati segala isinya, kecuali mendekati satu pohon. Iblis membisikkan tipu daya, bersumpah palsu bahwa ia penasihat yang tulus, dan mengatakan pohon itu adalah pohon kekekalan. Keduanya akhirnya memakan buahnya, maka tampaklah aurat mereka dan mereka menutupinya dengan daun-daun surga. Inilah pelanggaran pertama manusia — lahir dari kelalaian, bukan kesombongan seperti Iblis.', 'QS Al-Baqarah: 35–36 · QS Al-A''raf: 19–22 · QS Thaha: 117–121');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('adam', 4, 'Taubat yang Diterima dan Turun ke Bumi', 'Adam dan Hawa tidak berputus asa. Mereka menerima kalimat-kalimat dari Tuhannya lalu berdoa, "Rabbana zhalamna anfusana — Ya Tuhan kami, kami telah menzalimi diri kami sendiri; jika Engkau tidak mengampuni kami dan memberi rahmat kepada kami, niscaya kami termasuk orang-orang yang rugi." Allah menerima taubat keduanya, lalu menurunkan mereka ke bumi untuk menjalani kehidupan yang telah ditetapkan: bumi menjadi tempat tinggal dan ladang amal, dan petunjuk Allah akan datang silih berganti melalui para nabi.', 'QS Al-Baqarah: 37–39 · QS Al-A''raf: 23–25 · QS Thaha: 122–123');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('adam', 5, 'Habil dan Qabil: Darah Pertama di Bumi', 'Di antara anak-anak Adam, Al-Qur''an mengisahkan dua putranya yang mempersembahkan kurban. Kurban Habil diterima karena ketakwaannya, sedangkan kurban Qabil ditolak. Dengki membakar hati Qabil hingga ia membunuh saudaranya sendiri — pembunuhan pertama dalam sejarah manusia. Ia kemudian menyesal ketika seekor burung gagak mengajarinya cara menguburkan jenazah saudaranya. Dari kisah ini Allah menetapkan: membunuh satu jiwa tanpa hak seakan membunuh seluruh manusia.', 'QS Al-Ma''idah: 27–32');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('adam', 6, 'Ibrah Kisah Nabi Adam', 'Kisah Adam mengajarkan bahwa manusia mulia karena ilmu dan ketaatan, bukan karena asal penciptaan; bahwa dosa yang diikuti taubat lebih dicintai Allah daripada kesombongan yang menolak bersalah; dan bahwa permusuhan Iblis terhadap manusia adalah nyata dan abadi. Setiap anak Adam pernah berbuat salah, dan sebaik-baik orang yang bersalah adalah yang bertaubat.', 'QS Al-A''raf: 26–27 · QS Fathir: 6');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('idris', 1, 'Nabi yang Ditinggikan Derajatnya', 'Allah menyebut Idris dalam Al-Qur''an sebagai seorang yang sangat membenarkan (shiddiq) dan seorang nabi, lalu berfirman, "Dan Kami telah mengangkatnya ke martabat yang tinggi." Para ulama tafsir menyebut Idris hidup di antara masa Adam dan Nuh, termasuk nenek moyang Nabi Nuh. Ia dikenal sebagai orang pertama yang menulis dengan pena dan mengamati perbintangan serta hisab — karunia ilmu yang menjadi tanda kenabiannya.', 'QS Maryam: 56–57');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('idris', 2, 'Kesabaran dan Kesalehannya', 'Dalam surah Al-Anbiya, Idris disebut bersama Ismail dan Dzulkifli: "Semua mereka termasuk orang-orang yang sabar, dan Kami masukkan mereka ke dalam rahmat Kami. Sesungguhnya mereka termasuk orang-orang yang saleh." Al-Qur''an tidak memerinci kisah kaumnya; yang Allah tonjolkan dari Idris adalah pribadi penyabar yang terus beramal dan mengajarkan tauhid di zamannya.', 'QS Al-Anbiya: 85–86');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('idris', 3, 'Ibrah Kisah Nabi Idris', 'Sedikitnya rincian kisah Idris justru menegaskan pelajaran utamanya: kemuliaan seseorang di sisi Allah diukur dari kejujuran, kesabaran, dan ilmunya yang diamalkan. Derajat yang tinggi tidak diraih dengan kekuasaan, melainkan dengan istiqamah dalam kebenaran.', 'QS Maryam: 57');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('nuh', 1, 'Rasul Pertama untuk Kaum yang Menyembah Berhala', 'Setelah berabad-abad manusia bertauhid, kaum Nuh mulai menyembah patung orang-orang saleh mereka: Wadd, Suwa'', Yaghuts, Ya''uq, dan Nasr — nama-nama yang semula orang saleh, lalu dijadikan berhala oleh generasi berikutnya. Allah mengutus Nuh sebagai rasul untuk mengembalikan mereka kepada penyembahan Allah semata: "Wahai kaumku, sembahlah Allah, sekali-kali tidak ada tuhan bagimu selain Dia."', 'QS Nuh: 23 · QS Al-A''raf: 59 · QS Hud: 25–26');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('nuh', 2, 'Dakwah 950 Tahun Tanpa Lelah', 'Nuh berdakwah malam dan siang, sembunyi-sembunyi dan terang-terangan, selama sembilan ratus lima puluh tahun. Ia menjanjikan ampunan Allah, hujan yang deras, harta dan anak-anak bagi yang bertaubat. Namun kaumnya menyumbat telinga, menutupkan baju ke kepala, dan bertahan dalam kesombongan. Para pembesar menghina bahwa pengikut Nuh hanyalah orang-orang hina, dan menantang agar azab segera didatangkan.', 'QS Al-Ankabut: 14 · QS Nuh: 5–12 · QS Hud: 27–32');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('nuh', 3, 'Perintah Membangun Bahtera', 'Ketika Allah mewahyukan bahwa tidak akan beriman lagi dari kaumnya kecuali yang telah beriman, Nuh berdoa agar Allah tidak membiarkan seorang kafir pun tinggal di bumi. Allah memerintahkannya membangun bahtera di bawah pengawasan dan wahyu-Nya. Setiap kali para pembesar kaumnya lewat, mereka mengejeknya — membuat kapal besar jauh dari laut. Nuh menjawab, "Jika kamu mengejek kami, kami pun kelak akan mengejekmu sebagaimana kamu mengejek."', 'QS Hud: 36–39 · QS Nuh: 26–27 · QS Al-Mu''minun: 27');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('nuh', 4, 'Banjir Besar dan Tenggelamnya Sang Anak', 'Ketika tanur telah memancarkan air, Nuh membawa ke dalam bahtera sepasang dari tiap jenis makhluk, keluarganya, dan orang-orang beriman — yang jumlahnya hanya sedikit. Air memancar dari langit dan bumi, gelombang setinggi gunung. Nuh memanggil anaknya yang menjauh, "Wahai anakku, naiklah bersama kami!" Namun sang anak memilih berlindung ke gunung dan ikut tenggelam. Ketika Nuh memohon untuk anaknya, Allah menegaskan, "Ia bukan termasuk keluargamu; sesungguhnya perbuatannya tidak baik." Bahtera pun berlabuh di bukit Judiy.', 'QS Hud: 40–48 · QS Al-Qamar: 11–14');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('nuh', 5, 'Keluarga Bukan Jaminan Keselamatan', 'Istri Nuh termasuk yang kafir dan dibinasakan; Allah menjadikannya perumpamaan bahwa kedekatan nasab dengan orang saleh tidak menyelamatkan tanpa iman. Sebaliknya, keselamatan diraih siapa pun yang beriman meski seluruh dunia menentangnya.', 'QS At-Tahrim: 10 · QS Hud: 45–47');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('nuh', 6, 'Ibrah Kisah Nabi Nuh', 'Nuh adalah teladan kesabaran dakwah paling panjang dalam sejarah: hampir seribu tahun menyeru dengan segala cara tanpa putus asa. Kisahnya mengajarkan bahwa hidayah milik Allah semata, tugas dai hanyalah menyampaikan; dan bahwa kesyirikan sering bermula dari pengagungan berlebihan terhadap orang saleh.', 'QS Al-Ankabut: 14–15 · QS Ash-Shaffat: 75–82');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('hud', 1, 'Kaum ''Ad yang Perkasa di Ahqaf', 'Kaum ''Ad tinggal di Ahqaf, bukit-bukit pasir di wilayah Yaman, sesudah kaum Nuh. Mereka berbadan kuat dan membangun kota bermegah-megah — "Iram yang mempunyai bangunan-bangunan tinggi, yang belum pernah diciptakan sepertinya di negeri-negeri lain." Kekuatan itu membuat mereka sombong: "Siapakah yang lebih kuat daripada kami?" Allah mengutus Hud, saudara mereka sendiri, untuk menyeru kepada tauhid.', 'QS Al-Fajr: 6–8 · QS Fussilat: 15 · QS Al-A''raf: 65');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('hud', 2, 'Seruan Hud dan Kesombongan Kaumnya', 'Hud mengingatkan nikmat Allah: tubuh yang perkasa, tanah yang luas, dan kedudukan sebagai pengganti kaum Nuh. Ia tidak meminta upah sedikit pun. Namun para pembesar menuduhnya kurang akal dan pendusta. Mereka berkata, "Sama saja bagi kami, apakah engkau menasihati atau tidak." Hud berlepas diri dari sesembahan mereka dan bertawakal kepada Allah, "Tidak ada satu makhluk melata pun melainkan Allah yang memegang ubun-ubunnya."', 'QS Al-A''raf: 66–71 · QS Hud: 50–57 · QS Asy-Syu''ara: 123–140');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('hud', 3, 'Angin yang Membinasakan', 'Ketika azab datang, mereka melihat awan menghampiri lembah dan menyangkanya hujan. Padahal itu angin yang sangat dingin lagi kencang, ditimpakan tujuh malam delapan hari terus-menerus, hingga kaum itu bergelimpangan seperti batang-batang kurma yang lapuk. Hud dan orang-orang beriman diselamatkan dengan rahmat Allah.', 'QS Al-Ahqaf: 24–25 · QS Al-Haqqah: 6–8 · QS Hud: 58–60');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('hud', 4, 'Ibrah Kisah Nabi Hud', 'Kekuatan fisik, teknologi bangunan, dan kejayaan peradaban tidak berarti apa-apa di hadapan Allah bila disertai kesombongan. Angin — makhluk yang tak terlihat — cukup untuk meruntuhkan kaum yang bertanya "siapa yang lebih kuat dari kami". Kisah Hud juga meneladankan dai yang tegar sendirian menghadapi seluruh pembesar kaumnya.', 'QS Fussilat: 15–16 · QS Adz-Dzariyat: 41–42');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('saleh', 1, 'Kaum Tsamud Pemahat Gunung', 'Sesudah ''Ad, kaum Tsamud mewarisi negeri di Al-Hijr (antara Hijaz dan Syam). Mereka ahli memahat gunung menjadi rumah-rumah yang kokoh dan hidup makmur dengan kebun, mata air, tanaman, dan kurma. Allah mengutus Saleh, seorang yang sebelumnya sangat dihormati di tengah mereka, untuk menyeru: sembahlah Allah dan jangan berbuat kerusakan di bumi.', 'QS Al-A''raf: 73–74 · QS Al-Hijr: 80–82 · QS Asy-Syu''ara: 141–152');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('saleh', 2, 'Unta Betina sebagai Tanda dari Allah', 'Kaumnya menuntut bukti, maka Allah mengeluarkan seekor unta betina sebagai mukjizat yang nyata. Saleh berpesan: biarkan unta itu makan di bumi Allah, ia mendapat giliran minum sehari dan kalian sehari, dan jangan sekali-kali mengganggunya — "maka kamu akan ditimpa azab yang dekat."', 'QS Al-A''raf: 73 · QS Asy-Syu''ara: 155–156 · QS Al-Qamar: 27–28');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('saleh', 3, 'Penyembelihan Unta dan Datangnya Azab', 'Orang paling celaka di antara mereka bangkit menyembelih unta itu, didukung sembilan gerombolan perusak yang bahkan merencanakan membunuh Saleh dan keluarganya di malam hari. Allah menggagalkan makar itu. Tiga hari kemudian azab datang: suara menggelegar (shaihah) dan gempa membuat mereka mati bergelimpangan di rumah-rumah mereka. Saleh berpaling sambil berkata, "Wahai kaumku, sungguh aku telah menyampaikan amanat Tuhanku dan menasihatimu, tetapi kamu tidak menyukai orang yang memberi nasihat."', 'QS Asy-Syams: 11–15 · QS An-Naml: 45–53 · QS Al-A''raf: 77–79 · QS Hud: 61–68');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('saleh', 4, 'Ibrah Kisah Nabi Saleh', 'Mukjizat yang diminta sendiri pun tidak menjamin iman bila hati telah membatu — bahkan menjadi hujah yang mempercepat azab. Kisah Tsamud juga mengingatkan bahaya segelintir perusak yang dibiarkan: satu orang menyembelih, namun azab menimpa kaum yang meridhainya.', 'QS Asy-Syams: 14 · QS Al-Isra: 59');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ibrahim', 1, 'Pemuda yang Mencari Tuhan', 'Ibrahim tumbuh di tengah kaum penyembah berhala di negeri Babilonia; ayahnya, Azar, bahkan pembuat patung. Al-Qur''an mengabadikan perenungannya: ketika malam tiba ia melihat bintang, lalu bulan, lalu matahari — dan setiap kali yang dilihatnya terbenam, ia berkata, "Aku tidak menyukai yang terbenam." Hingga ia berikrar menghadapkan wajahnya kepada Dzat yang menciptakan langit dan bumi dengan lurus (hanif).', 'QS Al-An''am: 74–79 · QS Maryam: 41–48');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ibrahim', 2, 'Menghancurkan Berhala dan Diuji dengan Api', 'Ibrahim menghancurkan berhala-berhala kaumnya dan menyisakan yang terbesar, agar mereka bertanya kepadanya. Ketika ditanya, ia menjawab, "Tanyakanlah kepada patung besar itu!" — membungkam mereka dengan akal sehat mereka sendiri. Kalah berhujah, mereka memilih kekerasan: "Bakarlah dia!" Maka Allah berfirman, "Wahai api, jadilah dingin dan keselamatan bagi Ibrahim." Ia keluar dari api tanpa cedera. Di hadapan raja Namrud yang mengaku menghidupkan dan mematikan, Ibrahim menantang, "Allah menerbitkan matahari dari timur, maka terbitkanlah ia dari barat" — dan terdiamlah orang kafir itu.', 'QS Al-Anbiya: 51–70 · QS Al-Baqarah: 258 · QS Ash-Shaffat: 88–98');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ibrahim', 3, 'Hijrah, Keturunan, dan Doa-doanya', 'Ibrahim berhijrah meninggalkan negerinya demi Allah. Di usia tua ia dikaruniai Ismail dari Hajar, lalu Ishaq dari Sarah — kabar gembira yang dibawa para malaikat. Atas perintah Allah ia menempatkan Hajar dan Ismail di lembah Makkah yang tandus, seraya berdoa agar Allah menjadikan hati manusia condong kepada mereka dan memberi rezeki dari buah-buahan. Doa-doa Ibrahim menghiasi Al-Qur''an: memohon negeri yang aman, keturunan yang mendirikan salat, dan diutusnya seorang rasul dari anak cucunya — doa yang terjawab dengan diutusnya Muhammad ﷺ.', 'QS Ibrahim: 35–41 · QS Hud: 69–73 · QS Al-Baqarah: 126–129');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ibrahim', 4, 'Ujian Penyembelihan Ismail', 'Ketika Ismail beranjak besar, Ibrahim bermimpi menyembelihnya — dan mimpi para nabi adalah wahyu. Ia menyampaikannya kepada sang anak, yang menjawab dengan iman menakjubkan: "Wahai ayahku, kerjakanlah apa yang diperintahkan kepadamu; insya Allah engkau akan mendapatiku termasuk orang-orang yang sabar." Ketika keduanya telah berserah diri dan Ibrahim membaringkan anaknya, Allah memanggil, "Sungguh engkau telah membenarkan mimpi itu," lalu menebusnya dengan sembelihan yang besar. Peristiwa inilah yang diabadikan umat Islam setiap Idul Adha.', 'QS Ash-Shaffat: 99–111');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ibrahim', 5, 'Membangun Ka''bah dan Millah Hanifiyyah', 'Bersama Ismail, Ibrahim meninggikan fondasi Baitullah sambil berdoa, "Ya Tuhan kami, terimalah dari kami; sesungguhnya Engkau Maha Mendengar lagi Maha Mengetahui." Ia diperintahkan menyeru manusia untuk berhaji. Allah menjadikannya imam bagi seluruh manusia, kekasih-Nya (khalilullah), dan bapak para nabi: dari Ismail lahir garis Nabi Muhammad ﷺ, dari Ishaq lahir para nabi Bani Israil. Islam disebut millah Ibrahim — agama tauhid yang lurus.', 'QS Al-Baqarah: 124–132 · QS Al-Hajj: 26–27 · QS An-Nisa: 125 · QS An-Nahl: 120–123');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ibrahim', 6, 'Ibrah Kisah Nabi Ibrahim', 'Ibrahim meneladankan tauhid yang total: berani menghadapi ayah, kaum, raja, dan api demi kebenaran; menyerahkan keluarga dan anak kesayangan kepada perintah Allah. Setiap rakaat salat umat ini bershalawat untuknya — tanda betapa agung kedudukannya.', 'QS Al-Mumtahanah: 4 · QS An-Nahl: 120–122');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('luth', 1, 'Diutus kepada Kaum Sadum', 'Luth adalah keponakan Ibrahim yang beriman kepadanya dan ikut berhijrah. Allah mengutusnya kepada penduduk Sadum (Sodom), kaum yang melakukan kekejian yang belum pernah dilakukan seorang pun di alam ini: mendatangi sesama lelaki, merampok di jalan, dan mengerjakan kemungkaran di tempat pertemuan mereka.', 'QS Al-Ankabut: 26–29 · QS Al-A''raf: 80–81');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('luth', 2, 'Dakwah yang Dijawab dengan Ancaman Pengusiran', 'Luth menyeru mereka bertakwa dan meninggalkan kekejian, mengingatkan bahwa ia rasul yang terpercaya dan tidak meminta upah. Jawaban kaumnya justru: "Usirlah keluarga Luth dari negerimu; sesungguhnya mereka orang-orang yang menyucikan diri." Kesucian dianggap kejahatan — begitulah terbaliknya nilai pada kaum yang rusak.', 'QS Asy-Syu''ara: 160–167 · QS An-Naml: 54–56');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('luth', 3, 'Tamu-Tamu Malaikat dan Malam Penyelamatan', 'Para malaikat datang dalam rupa pemuda-pemuda tampan. Luth merasa sempit dadanya karena tahu tabiat kaumnya — dan benar, mereka berdatangan bergegas. Luth berkata, "Inilah putri-putri (kaum)ku, mereka lebih suci bagimu," namun mereka menolak. Ketika Luth berkata, "Seandainya aku mempunyai kekuatan untuk menolakmu," para tamu menyingkap jati diri: "Kami adalah utusan Tuhanmu; mereka tidak akan dapat mengganggumu." Allah membutakan mata kaum itu, dan Luth diperintahkan berjalan bersama keluarganya di akhir malam — tanpa menoleh — kecuali istrinya yang berkhianat.', 'QS Hud: 77–81 · QS Al-Hijr: 61–72 · QS Al-Qamar: 37');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('luth', 4, 'Negeri yang Dibalikkan', 'Saat fajar tiba, negeri itu dibalikkan: yang atas dijadikan bawah, dan hujan batu dari tanah yang terbakar menimpa mereka bertubi-tubi, setiap batu bertanda dari Tuhanmu. Bekas negeri itu berada di jalan yang masih dilalui manusia — tanda bagi orang-orang yang mau berpikir.', 'QS Hud: 82–83 · QS Al-Hijr: 73–77 · QS Ash-Shaffat: 133–138');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('luth', 5, 'Ibrah Kisah Nabi Luth', 'Kisah Luth adalah peringatan paling keras terhadap penyimpangan fitrah, sekaligus pelajaran bahwa ikatan pernikahan pun tidak menyelamatkan bila hati berkhianat kepada agama — istri Luth binasa bersama kaumnya. Dan bagi para dai: merasa lemah tidak menghalangi datangnya pertolongan Allah pada waktunya.', 'QS At-Tahrim: 10 · QS Al-Ankabut: 30–35');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ismail', 1, 'Bayi di Lembah Tandus dan Air Zamzam', 'Atas perintah Allah, Ibrahim menempatkan Hajar dan bayinya, Ismail, di lembah Makkah yang tidak bertanaman, di dekat lokasi Baitullah. Ketika bekal habis, Hajar berlari-lari antara bukit Shafa dan Marwah tujuh kali mencari air — sa''i yang kini diabadikan dalam manasik haji. Lalu memancarlah air zamzam di dekat kaki Ismail dengan izin Allah, dan lembah mati itu mulai dihuni manusia.', 'QS Ibrahim: 37 · HR Bukhari no. 3364 (kisah Hajar dan zamzam)');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ismail', 2, 'Anak yang Sabar Menghadapi Ujian Sembelihan', 'Ketika diberi tahu ayahnya tentang mimpi penyembelihan, Ismail — yang oleh Al-Qur''an disifati ghulam halim, anak yang sangat sabar — menjawab, "Wahai ayahku, kerjakanlah apa yang diperintahkan kepadamu." Keduanya berserah diri hingga Allah menebusnya dengan sembelihan yang besar. Ismail lulus dari ujian yang menjadikannya teladan kepasrahan bagi seluruh generasi.', 'QS Ash-Shaffat: 101–107');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ismail', 3, 'Membangun Ka''bah Bersama Sang Ayah', 'Ismail membantu ayahnya meninggikan fondasi Baitullah, dan keduanya berdoa agar Allah menerima amal itu serta membangkitkan dari keturunan mereka umat yang berserah diri. Ismail kemudian menetap di Makkah, menikah dengan penduduk Jurhum, dan menjadi nenek moyang bangsa Arab Musta''ribah — dari garis inilah Nabi Muhammad ﷺ dilahirkan.', 'QS Al-Baqarah: 127–129 · QS Ibrahim: 39');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ismail', 4, 'Nabi yang Menepati Janji', 'Allah memujinya secara khusus: "Ceritakanlah kisah Ismail di dalam Kitab; sesungguhnya ia adalah seorang yang benar janjinya, seorang rasul dan nabi. Ia menyuruh keluarganya untuk salat dan menunaikan zakat, dan ia seorang yang diridhai di sisi Tuhannya."', 'QS Maryam: 54–55 · QS Al-Anbiya: 85–86');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ismail', 5, 'Ibrah Kisah Nabi Ismail', 'Ismail mengajarkan bakti yang sempurna kepada orang tua dalam ketaatan kepada Allah, kesabaran menghadapi ujian sejak bayi hingga dewasa, dan keteguhan menepati janji. Jejak keluarganya — zamzam, sa''i, kurban, Ka''bah — dihidupkan umat Islam setiap tahun.', 'QS Ash-Shaffat: 108–111');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ishaq', 1, 'Kabar Gembira di Usia Senja', 'Para malaikat yang menuju negeri Luth singgah kepada Ibrahim membawa kabar gembira: seorang anak bernama Ishaq, dan setelah Ishaq, cucu bernama Ya''qub. Sarah tertawa keheranan — "Bagaimana aku akan melahirkan, padahal aku sudah tua dan suamiku pun sudah sangat tua?" Para malaikat menjawab, "Apakah engkau merasa heran terhadap ketetapan Allah?"', 'QS Hud: 69–73 · QS Al-Hijr: 51–56 · QS Adz-Dzariyat: 24–30');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ishaq', 2, 'Nabi dari Keturunan yang Diberkahi', 'Allah berfirman, "Dan Kami beri ia kabar gembira dengan Ishaq, seorang nabi yang termasuk orang-orang yang saleh. Kami limpahkan keberkahan atasnya dan atas Ishaq." Dari Ishaq lahir Ya''qub (Israil), dan dari keturunannya berlanjut silsilah panjang para nabi Bani Israil: Yusuf, Musa, Daud, Sulaiman, hingga Isa.', 'QS Ash-Shaffat: 112–113 · QS Al-Anbiya: 72–73');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ishaq', 3, 'Hamba Pilihan yang Mengingatkan Negeri Akhirat', 'Al-Qur''an menyebut Ibrahim, Ishaq, dan Ya''qub sebagai hamba-hamba yang mempunyai kekuatan dan pandangan yang tajam, yang Allah sucikan dengan akhlak yang tinggi: selalu mengingatkan manusia kepada negeri akhirat. Ishaq meneruskan dakwah tauhid ayahnya di negeri Syam hingga wafatnya.', 'QS Shad: 45–47 · QS Al-Baqarah: 133');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ishaq', 4, 'Ibrah Kisah Nabi Ishaq', 'Kelahiran Ishaq membuktikan bahwa karunia Allah tidak dibatasi hukum kebiasaan — usia senja bukan penghalang bagi ketetapan-Nya. Keberkahan sejati sebuah keluarga adalah lahirnya generasi yang meneruskan tauhid, bukan sekadar keturunan yang banyak.', 'QS Hud: 73 · QS Ibrahim: 39');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('yaqub', 1, 'Israil, Bapak Dua Belas Keturunan', 'Ya''qub bin Ishaq bin Ibrahim — disebut juga Israil — adalah nabi yang darinya lahir dua belas putra, cikal bakal suku-suku (asbath) Bani Israil. Ia mewarisi dakwah tauhid kakek dan ayahnya, dan Al-Qur''an mengabadikannya sebagai hamba pilihan yang selalu mengingatkan kepada negeri akhirat.', 'QS Shad: 45–47 · QS Al-Baqarah: 136 · QS Yusuf: 4–6');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('yaqub', 2, 'Ujian Kehilangan Yusuf', 'Ketika putra-putranya membuang Yusuf dan datang membawa baju berlumur darah palsu, Ya''qub tidak tertipu, namun memilih sikap yang diabadikan Al-Qur''an: "Fashabrun jamil — maka kesabaran yang baik itulah (kesabaranku), dan Allah sajalah yang dimohon pertolongan-Nya." Bertahun-tahun ia memendam duka hingga kedua matanya memutih karena menangis, namun tak sekali pun ia berkeluh kesah kepada selain Allah: "Sesungguhnya hanya kepada Allah aku mengadukan kesusahan dan kesedihanku."', 'QS Yusuf: 16–18 · QS Yusuf: 84–86');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('yaqub', 3, 'Larangan Berputus Asa dari Rahmat Allah', 'Meski kehilangan Yusuf lalu Bunyamin, Ya''qub tetap memerintahkan anak-anaknya mencari keduanya: "Wahai anak-anakku, pergilah kamu, carilah berita tentang Yusuf dan saudaranya, dan jangan berputus asa dari rahmat Allah. Sesungguhnya tidak berputus asa dari rahmat Allah melainkan kaum yang kafir." Keyakinannya terbukti: penglihatannya kembali dengan baju Yusuf, dan seluruh keluarga berkumpul di Mesir dalam kemuliaan.', 'QS Yusuf: 87 · QS Yusuf: 93–100');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('yaqub', 4, 'Wasiat di Ambang Wafat', 'Al-Qur''an mengabadikan detik-detik wafatnya: ia bertanya kepada anak-anaknya, "Apa yang kamu sembah sepeninggalku?" Mereka menjawab, "Kami akan menyembah Tuhanmu dan Tuhan nenek moyangmu — Ibrahim, Ismail, dan Ishaq — Tuhan Yang Maha Esa, dan kami hanya tunduk patuh kepada-Nya." Itulah warisan terbesar seorang ayah: memastikan tauhid anak-anaknya.', 'QS Al-Baqarah: 132–133');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('yaqub', 5, 'Ibrah Kisah Nabi Ya''qub', 'Ya''qub adalah madrasah kesabaran: ujian datang dari anak-anaknya sendiri, berlangsung puluhan tahun, namun ia menutup setiap duka dengan husnuzhan kepada Allah. Kisahnya mengajarkan seni mendidik anak yang bersalah — menegur tanpa memutus kasih, hingga akhirnya merekalah yang memohon diampunkan.', 'QS Yusuf: 98 · QS Yusuf: 83');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('yusuf', 1, 'Mimpi Sang Bocah dan Kedengkian Saudara', 'Yusuf kecil bermimpi sebelas bintang, matahari, dan bulan bersujud kepadanya. Ya''qub memintanya merahasiakan mimpi itu dari saudara-saudaranya. Namun kedengkian telah tumbuh: para saudara merasa ayah lebih mencintai Yusuf, lalu bersepakat membuangnya ke dasar sumur dan pulang membawa tangisan palsu serta baju berlumur darah dusta.', 'QS Yusuf: 4–18');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('yusuf', 2, 'Dijual Murah dan Tumbuh di Rumah Al-Aziz', 'Kafilah yang menimba air menemukan Yusuf dan menjualnya ke Mesir dengan harga murah, beberapa dirham saja. Al-Aziz, pembesar Mesir, membelinya dan memuliakannya. Ketika Yusuf mencapai kedewasaannya, Allah menganugerahinya hikmah dan ilmu — "demikianlah Kami memberi balasan kepada orang-orang yang berbuat baik."', 'QS Yusuf: 19–22');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('yusuf', 3, 'Godaan Istri Al-Aziz dan Penjara yang Dipilih', 'Istri Al-Aziz menggodanya di balik pintu-pintu yang terkunci. Yusuf menjawab, "Aku berlindung kepada Allah!" Ia berlari ke pintu hingga bajunya robek dari belakang — bukti yang menunjukkan kebenarannya. Ketika para wanita kota mempergunjingkan, mereka pun terpesona hingga mengiris tangan sendiri. Diancam penjara bila menolak, Yusuf berdoa, "Wahai Tuhanku, penjara lebih aku sukai daripada memenuhi ajakan mereka." Ia dipenjara meski terbukti tak bersalah.', 'QS Yusuf: 23–35');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('yusuf', 4, 'Takwil Mimpi dari Balik Jeruji', 'Di penjara Yusuf berdakwah tauhid dan menakwilkan mimpi dua pemuda pelayan raja. Bertahun kemudian, raja bermimpi tujuh sapi gemuk dimakan tujuh sapi kurus. Yusuf menakwilkannya: tujuh tahun subur untuk menanam dan menyimpan, tujuh tahun paceklik, lalu tahun pertolongan. Ia menolak keluar penjara sebelum namanya dibersihkan — dan para wanita pun mengakui kesuciannya di hadapan raja.', 'QS Yusuf: 36–53');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('yusuf', 5, 'Bendahara Negeri dan Pertemuan Kembali', 'Raja menjadikan Yusuf orang kepercayaan, dan Yusuf meminta amanah gudang-gudang negeri: "Sesungguhnya aku pandai menjaga lagi berpengetahuan." Saat paceklik melanda, saudara-saudaranya datang membeli gandum tanpa mengenalinya. Melalui rangkaian peristiwa yang tersusun rapi — menahan Bunyamin, lalu menyingkap jati diri — Yusuf berkata, "Tidak ada cercaan terhadap kamu pada hari ini; Allah mengampuni kamu." Seluruh keluarga diboyong ke Mesir, dan sujudlah sebelas saudara beserta ayah-ibunya: takwil mimpi masa kecilnya.', 'QS Yusuf: 54–100');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('yusuf', 6, 'Doa Pamungkas dan Ibrah Kisah Yusuf', 'Yusuf menutup kisahnya dengan doa yang menghimpun syukur dan harap: "Wahai Tuhanku, Engkau telah menganugerahkan kepadaku sebagian kerajaan dan mengajarkan takwil mimpi... wafatkanlah aku dalam keadaan muslim dan gabungkanlah aku dengan orang-orang saleh." Allah menyebut kisah ini ahsanul qashash — sebaik-baik kisah: tentang iffah (menjaga kesucian), memaafkan total tanpa dendam, profesionalitas amanah, dan janji bahwa akhir yang baik adalah milik orang bertakwa.', 'QS Yusuf: 101 · QS Yusuf: 3 · QS Yusuf: 90');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ayyub', 1, 'Hamba yang Diuji Setelah Kelapangan', 'Ayyub adalah nabi dari keturunan Ibrahim yang semula dikaruniai harta melimpah, keluarga besar, dan kesehatan. Lalu Allah mengujinya bertubi-tubi: hartanya habis, anak-anaknya wafat, dan tubuhnya ditimpa penyakit bertahun-tahun hingga manusia menjauhinya — hanya istrinya yang setia merawat.', 'QS Shad: 41 · QS Al-Anbiya: 83');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ayyub', 2, 'Sabar yang Menjadi Teladan Abadi', 'Dalam sakit yang panjang itu Ayyub tidak pernah mencela takdir. Doanya pun tersusun santun, tanpa protes: "(Ya Tuhanku), sesungguhnya aku telah ditimpa penyakit, dan Engkau adalah Yang Maha Penyayang di antara semua penyayang." Ia tidak menuntut, hanya menyebut keadaannya dan memuji Tuhannya. Allah mengabadikan pujian untuknya: "Sesungguhnya Kami dapati dia seorang yang sabar; sebaik-baik hamba, sesungguhnya dia sangat taat (kepada Tuhannya)."', 'QS Al-Anbiya: 83 · QS Shad: 44');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ayyub', 3, 'Kesembuhan dan Penggantian yang Lebih Baik', 'Allah memerintahkannya menghentakkan kaki: memancarlah mata air yang sejuk untuk mandi dan minum, dan sembuhlah ia. Allah mengembalikan keluarganya dan melipatgandakannya sebagai rahmat dari-Nya dan pelajaran bagi orang-orang yang berakal. Untuk menepati sumpahnya terhadap istrinya tanpa menyakitinya, Allah memberi keringanan: memukul dengan seikat rumput — kelembutan hukum bagi hamba yang tulus.', 'QS Shad: 42–44 · QS Al-Anbiya: 84');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ayyub', 4, 'Ibrah Kisah Nabi Ayyub', 'Ayyub membuktikan bahwa musibah bukan tanda kebencian Allah; justru ujian menaikkan derajat hamba yang ridha. Adab doanya mengajarkan cara mengadu tanpa menggugat, dan kesetiaan istrinya mengajarkan makna pendamping yang saleh dalam badai kehidupan.', 'QS Al-Baqarah: 155–157 · QS Shad: 44');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('syuaib', 1, 'Khatibul Anbiya di Negeri Madyan', 'Syu''aib diutus kepada penduduk Madyan, kaum yang menyembah Aikah (pohon besar) dan terkenal curang dalam takaran dan timbangan. Karena ketajaman dan keindahan tuturnya, para ulama menjulukinya khatibul anbiya — ahli pidatonya para nabi. Ia menyeru, "Sembahlah Allah, dan penuhilah takaran dan timbangan dengan adil; janganlah kamu merugikan manusia terhadap hak-hak mereka."', 'QS Hud: 84–85 · QS Al-A''raf: 85 · QS Asy-Syu''ara: 176–183');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('syuaib', 2, 'Ekonomi yang Bersih adalah Bagian dari Iman', 'Kaumnya mengejek, "Apakah salatmu menyuruhmu agar kami meninggalkan apa yang disembah nenek moyang kami, atau melarang kami berbuat terhadap harta kami sekehendak kami?" Syu''aib menjawab bahwa ia hanya menghendaki perbaikan (ishlah) sebatas kemampuannya: "Sisa (keuntungan halal) dari Allah lebih baik bagimu jika kamu orang beriman." Iman, dalam dakwah Syu''aib, tidak berhenti di masjid — ia mengatur pasar.', 'QS Hud: 86–88 · QS Al-A''raf: 86–87');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('syuaib', 3, 'Ancaman Pengusiran dan Datangnya Azab', 'Para pembesar mengancam mengusir Syu''aib dan pengikutnya bila tidak kembali kepada agama mereka. Ketika segala nasihat ditolak, azab datang: hari yang dinaungi awan (yaumuzh-zhullah) — mereka berkumpul di bawah naungan itu mencari kesejukan, lalu turunlah api menyambar; disusul suara menggelegar dan gempa hingga mereka mati bergelimpangan di rumah-rumah, "seolah-olah mereka belum pernah berdiam di tempat itu."', 'QS Al-A''raf: 88–92 · QS Asy-Syu''ara: 189 · QS Hud: 94–95');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('syuaib', 4, 'Ibrah Kisah Nabi Syu''aib', 'Kecurangan ekonomi adalah dosa yang membinasakan umat, setara bahayanya dengan kesyirikan dalam daftar dakwah Syu''aib. Kisahnya juga mengabadikan prinsip setiap pembaharu: "Aku tidak bermaksud menyalahi kamu dengan mengerjakan apa yang aku larang; aku hanya menghendaki perbaikan selama aku masih berkesanggupan."', 'QS Hud: 88 · QS Al-Muthaffifin: 1–6');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('musa', 1, 'Bayi yang Dihanyutkan ke Sungai Nil', 'Fir''aun menindas Bani Israil dan menyembelih setiap bayi lelaki mereka. Ketika Musa lahir, Allah mengilhamkan kepada ibunya agar menyusuinya, dan bila khawatir, menghanyutkannya ke sungai dalam peti — "Jangan takut dan jangan bersedih; sesungguhnya Kami akan mengembalikannya kepadamu dan menjadikannya salah seorang rasul." Peti itu dipungut keluarga Fir''aun; istri Fir''aun, Asiyah, memohon agar bayi itu tidak dibunuh. Allah mengharamkan Musa menyusu kepada selain ibunya, hingga sang ibu dipanggil ke istana sebagai ibu susuan — janji Allah terpenuhi.', 'QS Al-Qasas: 3–13 · QS Thaha: 37–40');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('musa', 2, 'Dari Istana ke Madyan', 'Musa tumbuh di istana Fir''aun dengan tubuh kuat dan jiwa pembela. Suatu hari ia menolong seorang Bani Israil dan meninju lawannya hingga tewas tanpa sengaja. Ia beristighfar dan diampuni, lalu keluar dari kota dengan takut. Di Madyan ia menolong dua putri lelaki tua saleh memberi minum ternak, lalu bekerja delapan hingga sepuluh tahun sebagai mahar pernikahannya. Di sinilah Allah menempa calon pemimpin besar itu dengan kesederhanaan.', 'QS Al-Qasas: 14–28');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('musa', 3, 'Wahyu di Lembah Suci Thuwa', 'Dalam perjalanan pulang, Musa melihat api di sisi gunung Thur. Di sana Allah berbicara langsung kepadanya: "Sesungguhnya Aku inilah Allah, tidak ada tuhan selain Aku, maka sembahlah Aku dan dirikanlah salat untuk mengingat-Ku." Tongkatnya menjadi ular, tangannya bercahaya putih — dua mukjizat untuk menghadapi Fir''aun. Musa memohon: lapangkan dadaku, mudahkan urusanku, lepaskan kekakuan lidahku, dan jadikan Harun saudaraku sebagai pembantuku. Allah mengabulkan seluruhnya.', 'QS Thaha: 9–48 · QS Al-Qasas: 29–35 · QS An-Naml: 7–12');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('musa', 4, 'Menghadapi Fir''aun dan Para Penyihir', 'Musa dan Harun menyampaikan risalah dengan perkataan yang lembut, namun Fir''aun menyombongkan diri, bahkan mengaku, "Akulah tuhanmu yang paling tinggi." Ia mengumpulkan para penyihir seluruh negeri. Ketika tali dan tongkat mereka tampak merayap oleh sihir, Allah meneguhkan Musa: "Lemparkanlah tongkatmu!" Tongkat itu menelan semua kepalsuan. Para penyihir — yang paling tahu batas sihir — langsung bersujud: "Kami beriman kepada Tuhan Harun dan Musa," dan tetap teguh meski Fir''aun mengancam memotong tangan-kaki mereka dan menyalib mereka.', 'QS Thaha: 42–73 · QS Asy-Syu''ara: 10–51 · QS An-Nazi''at: 24');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('musa', 5, 'Laut Terbelah dan Kebinasaan Fir''aun', 'Setelah bertahun-tahun ayat dan azab peringatan (belalang, kutu, katak, darah) tidak menundukkan Fir''aun, Allah memerintahkan Musa membawa Bani Israil keluar di malam hari. Di tepi laut, pasukan Fir''aun menyusul; kaumnya panik, "Kita benar-benar tersusul!" Musa menjawab dengan keyakinan yang menggetarkan: "Sekali-kali tidak! Sesungguhnya Tuhanku bersamaku, Dia akan memberiku petunjuk." Tongkat dipukulkan, laut terbelah menjadi jalan-jalan kering. Bani Israil menyeberang; Fir''aun dan bala tentaranya ditenggelamkan — dan jasadnya diselamatkan Allah menjadi tanda bagi generasi sesudahnya.', 'QS Asy-Syu''ara: 52–68 · QS Al-A''raf: 130–136 · QS Yunus: 90–92');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('musa', 6, 'Taurat, Anak Sapi, dan Ujian Sesudah Kemenangan', 'Musa bermunajat empat puluh malam menerima Taurat. Sepeninggalnya, Samiri membuatkan patung anak sapi bersuara, dan sebagian kaum menyembahnya — padahal baru saja diselamatkan. Musa kembali dengan marah dan sedih, menegur Harun, membakar patung itu, dan memerintahkan kaumnya bertaubat. Perjalanan Bani Israil kemudian dipenuhi pembangkangan: menolak masuk tanah suci ("Pergilah engkau bersama Tuhanmu, dan berperanglah kamu berdua"), hingga dihukum tersesat empat puluh tahun di padang Tih.', 'QS Thaha: 83–98 · QS Al-A''raf: 142–155 · QS Al-Ma''idah: 20–26');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('musa', 7, 'Belajar kepada Khidir', 'Ketika ditanya siapa manusia paling berilmu, Musa menjawab dirinya — maka Allah menegurnya dan mengutusnya belajar kepada seorang hamba saleh (Khidir) di pertemuan dua laut. Tiga peristiwa — melubangi perahu, membunuh seorang anak, menegakkan dinding tanpa upah — mengajarkan bahwa di balik takdir yang tampak buruk tersimpan hikmah yang tidak diketahui manusia. "Dan di atas setiap pemilik ilmu ada yang lebih mengetahui."', 'QS Al-Kahfi: 60–82 · QS Yusuf: 76');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('musa', 8, 'Ibrah Kisah Nabi Musa', 'Musa adalah nabi yang paling banyak disebut dalam Al-Qur''an — kisah perjuangan melawan tirani, memimpin umat yang keras kepala, dan terus belajar meski berkedudukan tinggi. Allah menyebutnya kalimullah, yang diajak bicara langsung. Kisahnya menghibur setiap pejuang kebenaran: tirani sebesar apa pun runtuh, dan Allah tidak pernah menyia-nyiakan orang yang berkata, "Sesungguhnya Tuhanku bersamaku."', 'QS Al-Ahzab: 69 · QS An-Nisa: 164 · QS Asy-Syu''ara: 62');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('harun', 1, 'Saudara yang Diminta dalam Doa', 'Harun diangkat menjadi nabi atas permintaan Musa dalam munajatnya di Thuwa: "Jadikanlah untukku seorang pembantu dari keluargaku, yaitu Harun saudaraku; teguhkanlah kekuatanku dengannya dan jadikanlah ia sekutu dalam urusanku." Allah menjawab, "Sungguh telah diperkenankan permintaanmu, wahai Musa." Al-Qur''an menyebut Harun lebih fasih lisannya, mendampingi Musa menghadapi Fir''aun.', 'QS Thaha: 29–36 · QS Al-Qasas: 34–35 · QS Al-Furqan: 35');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('harun', 2, 'Diuji Memimpin Kaum yang Menyembah Anak Sapi', 'Ketika Musa bermunajat empat puluh malam, Harun ditinggalkan memimpin Bani Israil. Saat Samiri menyesatkan mereka dengan patung anak sapi, Harun telah menasihati, "Wahai kaumku, sesungguhnya kamu hanya diberi cobaan dengannya, dan sesungguhnya Tuhanmu ialah Yang Maha Pemurah, maka ikutilah aku." Namun mereka mengancamnya. Ketika Musa kembali dan menarik kepalanya dengan marah, Harun menjelaskan bahwa ia menahan diri demi menjaga persatuan Bani Israil hingga Musa kembali — dan Musa pun mendoakan ampunan bagi keduanya.', 'QS Thaha: 90–94 · QS Al-A''raf: 150–151');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('harun', 3, 'Ibrah Kisah Nabi Harun', 'Harun meneladankan kekuatan dakwah berjamaah: risalah besar butuh pendamping yang menguatkan. Ia juga mengajarkan fikih prioritas seorang pemimpin — menimbang antara menindak kemungkaran dan menjaga persatuan umat. Allah mengabadikan salam untuk keduanya: "Salamun ''ala Musa wa Harun."', 'QS Ash-Shaffat: 114–122');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('dzulkifli', 1, 'Hamba yang Sabar dan Menepati Tanggungan', 'Dzulkifli disebut dalam Al-Qur''an di antara para nabi pilihan: "Dan (ingatlah kisah) Ismail, Idris, dan Dzulkifli. Semua mereka termasuk orang-orang yang sabar." Namanya bermakna "pemilik tanggungan" — para mufasir meriwayatkan bahwa ia menyanggupi menanggung urusan kaumnya: berpuasa di siang hari, beribadah di malam hari, dan memutuskan hukum tanpa marah, lalu ia menepati seluruh tanggungan itu.', 'QS Al-Anbiya: 85–86 · QS Shad: 48');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('dzulkifli', 2, 'Ibrah Kisah Nabi Dzulkifli', 'Al-Qur''an memilih menonjolkan satu sifat Dzulkifli: sabar dalam menunaikan komitmen. Kemuliaan tidak selalu lahir dari kisah yang dramatis — konsistensi menepati amanah harian pun mengangkat seorang hamba ke dalam rahmat Allah dan barisan orang-orang pilihan.', 'QS Shad: 48');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('daud', 1, 'Pemuda yang Menumbangkan Jalut', 'Dalam pasukan kecil Thalut yang lolos ujian sungai, Daud muda maju menghadapi raksasa Jalut. Dengan izin Allah, Daud membunuhnya — dan sesudah itu Allah menganugerahinya kerajaan dan hikmah serta mengajarinya apa yang Dia kehendaki. Al-Qur''an menutup kisah ini dengan kaidah abadi: "Kalau bukan karena Allah menolak (keganasan) sebagian manusia dengan sebagian yang lain, pasti rusaklah bumi."', 'QS Al-Baqarah: 246–251');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('daud', 2, 'Kerajaan, Zabur, dan Gunung yang Bertasbih', 'Allah menghimpun pada Daud kenabian dan kerajaan, menurunkan kepadanya Zabur, dan memberinya suara yang begitu indah hingga gunung-gunung dan burung-burung ikut bertasbih bersamanya di waktu pagi dan petang. Allah melunakkan besi di tangannya; ia menempa baju-baju perang yang rapi anyamannya — nabi yang makan dari hasil kerja tangannya sendiri, sebagaimana dipuji Rasulullah ﷺ.', 'QS Saba: 10–11 · QS Al-Anbiya: 79–80 · QS An-Nisa: 163 · HR Bukhari no. 2072');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('daud', 3, 'Hakim yang Diuji dan Segera Bertaubat', 'Al-Qur''an mengisahkan dua orang berperkara yang memanjat mihrabnya: pemilik sembilan puluh sembilan ekor kambing menuntut satu-satunya kambing saudaranya. Daud menyadari ujian di balik perkara itu, maka ia menyungkur sujud dan bertaubat — "lalu Kami mengampuninya; ia mempunyai kedudukan yang dekat di sisi Kami dan tempat kembali yang baik." Allah lalu mengukuhkannya: "Wahai Daud, Kami menjadikanmu khalifah di bumi, maka putuskanlah perkara di antara manusia dengan adil dan janganlah mengikuti hawa nafsu."', 'QS Shad: 21–26');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('daud', 4, 'Ibadah dan Puasa yang Paling Dicintai Allah', 'Rasulullah ﷺ bersabda bahwa salat yang paling dicintai Allah adalah salat Daud — tidur separuh malam, bangun sepertiganya, tidur seperenamnya — dan puasa yang paling dicintai Allah adalah puasa Daud: sehari berpuasa, sehari berbuka. Di tengah kekuasaan yang luas, ia tetap awwab — hamba yang selalu kembali kepada Allah.', 'HR Bukhari no. 1131 · QS Shad: 17');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('daud', 5, 'Ibrah Kisah Nabi Daud', 'Daud menghimpun apa yang jarang terhimpun: kekuatan militer, kekuasaan, seni suara yang menggetarkan, keterampilan kerja, dan ibadah yang dahsyat. Kisahnya menegaskan bahwa kekuasaan adalah amanah peradilan yang adil, dan bahwa orang besar bukan yang tak pernah tergelincir, melainkan yang paling cepat kembali.', 'QS Shad: 17–20 · QS Al-Baqarah: 251');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('sulaiman', 1, 'Pewaris Daud yang Memohon Kerajaan Tanpa Tanding', 'Sulaiman mewarisi ilmu dan kerajaan ayahnya, Daud. Ia pernah diuji, lalu berdoa dengan doa yang diabadikan: "Ya Tuhanku, ampunilah aku dan anugerahkanlah kepadaku kerajaan yang tidak dimiliki oleh siapa pun setelahku." Allah mengabulkannya: angin tunduk berhembus ke mana ia perintahkan, para jin bekerja membangun gedung-gedung tinggi dan patung, piring-piring sebesar kolam, serta menyelam mengambil mutiara — semuanya dengan izin Allah.', 'QS Shad: 30–40 · QS Saba: 12–13 · QS Al-Anbiya: 81–82');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('sulaiman', 2, 'Memahami Bahasa Burung dan Semut', 'Allah mengajarkan Sulaiman bahasa burung dan hewan. Ketika pasukannya melewati lembah semut, seekor semut berseru, "Wahai semut-semut, masuklah ke sarang-sarangmu agar kamu tidak diinjak Sulaiman dan tentaranya sedang mereka tidak menyadari." Sulaiman tersenyum mendengarnya, lalu berdoa — bukan membanggakan kesaktian, melainkan memohon: "Ya Tuhanku, anugerahkanlah aku (kemampuan) untuk mensyukuri nikmat-Mu."', 'QS An-Naml: 15–19');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('sulaiman', 3, 'Hud-hud dan Ratu Negeri Saba''', 'Burung hud-hud membawa berita tentang negeri Saba'' yang dipimpin seorang ratu bertakhta megah, menyembah matahari. Sulaiman mengirim surat yang dibuka dengan Bismillahirrahmanirrahim, mengajak berserah diri kepada Allah. Setelah utusan dan hadiah ratu ditolak, Sulaiman meminta takhtanya didatangkan — seorang berilmu dari Al-Kitab menghadirkannya sekejap mata sebelum ia berkedip. Ratu Balqis akhirnya masuk istana berlantai kaca yang disangkanya kolam, lalu berikrar: "Ya Tuhanku, sesungguhnya aku telah menzalimi diriku, dan aku berserah diri bersama Sulaiman kepada Allah, Tuhan seluruh alam."', 'QS An-Naml: 20–44');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('sulaiman', 4, 'Wafat yang Menyingkap Kelemahan Jin', 'Sulaiman wafat dalam keadaan berdiri bertelekan tongkat, dan para jin terus bekerja keras karena mengira ia masih mengawasi. Baru setelah rayap memakan tongkatnya dan tubuhnya tersungkur, nyatalah bahwa jin tidak mengetahui hal gaib — runtuhnya kepercayaan manusia yang menyangka jin mengetahui yang tersembunyi.', 'QS Saba: 14');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('sulaiman', 5, 'Ibrah Kisah Nabi Sulaiman', 'Kekayaan dan kekuasaan tanpa batas tidak melalaikan Sulaiman: setiap karunia ia sebut sebagai "karunia Tuhanku, untuk mengujiku apakah aku bersyukur atau kufur." Kisahnya adalah dalil bahwa dunia boleh berada di tangan, asal tidak masuk ke dalam hati — dan bahwa dakwah dapat berjalan lewat surat, diplomasi, dan kearifan.', 'QS An-Naml: 40 · QS Shad: 30');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ilyas', 1, 'Menentang Penyembahan Ba''l', 'Ilyas diutus kepada kaumnya (penduduk Ba''labak, dari Bani Israil) yang menyembah berhala bernama Ba''l. Seruannya diabadikan Al-Qur''an: "Mengapa kamu tidak bertakwa? Patutkah kamu menyembah Ba''l dan kamu tinggalkan sebaik-baik pencipta, yaitu Allah, Tuhanmu dan Tuhan nenek moyangmu yang terdahulu?"', 'QS Ash-Shaffat: 123–126');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ilyas', 2, 'Didustakan Kaum, Dimuliakan Allah', 'Kaumnya mendustakannya, maka mereka akan diseret ke azab — kecuali hamba-hamba Allah yang ikhlas. Allah mengekalkan nama baiknya pada generasi-generasi kemudian: "Salamun ''ala Ilyasin — kesejahteraan dilimpahkan atas Ilyas. Sesungguhnya demikianlah Kami memberi balasan kepada orang-orang yang berbuat baik."', 'QS Ash-Shaffat: 127–132');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ilyas', 3, 'Ibrah Kisah Nabi Ilyas', 'Ukuran keberhasilan dakwah bukan banyaknya pengikut, melainkan tuntasnya penyampaian dan keikhlasan. Meski didustakan mayoritas kaumnya, Ilyas dikenang langit dan bumi dengan salam kesejahteraan.', 'QS Ash-Shaffat: 130–132 · QS Al-An''am: 85');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ilyasa', 1, 'Penerus Dakwah Ilyas', 'Ilyasa'' (Alyasa'') disebut dua kali dalam Al-Qur''an di antara para nabi yang dilebihkan derajatnya atas seluruh alam. Para mufasir menyebutnya murid dan penerus Ilyas di tengah Bani Israil, melanjutkan seruan tauhid setelah gurunya.', 'QS Al-An''am: 86 · QS Shad: 48');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ilyasa', 2, 'Termasuk Orang-Orang Pilihan', 'Allah menyebutnya dalam barisan al-akhyar — orang-orang yang paling baik: "Dan ingatlah Ismail, Ilyasa'', dan Dzulkifli. Semuanya termasuk orang-orang yang paling baik." Penyebutan singkat ini adalah rekomendasi langit yang tidak membutuhkan panjangnya cerita.', 'QS Shad: 48');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('ilyasa', 3, 'Ibrah Kisah Nabi Ilyasa''', 'Regenerasi dakwah adalah sunnah para nabi: Ilyas menyiapkan Ilyasa'', sebagaimana Musa menyiapkan Yusya''. Estafet kebenaran tidak boleh terputus oleh wafatnya seorang dai.', 'QS Al-An''am: 87–90');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('yunus', 1, 'Meninggalkan Kaum Sebelum Waktunya', 'Yunus diutus kepada penduduk Ninawa yang berjumlah seratus ribu orang lebih. Lama menyeru tanpa hasil, ia pergi meninggalkan mereka dalam keadaan marah sebelum ada izin Allah, mengira Allah tidak akan menyempitkan keadaannya. Ia menumpang kapal yang sarat muatan; ketika badai mengharuskan pengurangan beban, undian jatuh kepadanya berkali-kali, maka ia dilemparkan ke laut dan ditelan ikan besar.', 'QS Ash-Shaffat: 139–142 · QS Al-Anbiya: 87');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('yunus', 2, 'Doa dalam Tiga Kegelapan', 'Dalam gelapnya malam, laut, dan perut ikan, Yunus menyeru dengan doa yang menjadi warisan seluruh orang yang terhimpit: "La ilaha illa anta, subhanaka, inni kuntu minazh-zhalimin — tidak ada tuhan selain Engkau, Mahasuci Engkau, sesungguhnya aku termasuk orang-orang yang zalim." Allah berfirman, "Maka Kami kabulkan doanya dan Kami selamatkan dia dari kedukaan; demikianlah Kami menyelamatkan orang-orang beriman." Kalau bukan karena ia termasuk orang yang banyak bertasbih, niscaya ia tinggal di perut ikan sampai hari berbangkit.', 'QS Al-Anbiya: 87–88 · QS Ash-Shaffat: 143–144');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('yunus', 3, 'Kaum yang Beriman Seluruhnya', 'Yunus dicampakkan ke daratan dalam keadaan sakit, dan Allah menumbuhkan pohon sejenis labu menaunginya. Sementara itu kaum Ninawa — satu-satunya umat dalam Al-Qur''an yang beriman seluruhnya setelah melihat tanda azab — bertaubat, maka Allah mengangkat azab dan memberi mereka kesenangan hingga waktu tertentu. Yunus kembali kepada kaum yang kini beriman, dan Allah mengutusnya kepada seratus ribu orang atau lebih.', 'QS Ash-Shaffat: 145–148 · QS Yunus: 98');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('yunus', 4, 'Ibrah Kisah Nabi Yunus', 'Rasulullah ﷺ bersabda bahwa doa Dzun-Nun ini tidak dipanjatkan seorang muslim dalam kesulitan apa pun melainkan Allah mengabulkannya. Kisah Yunus mengajarkan bahwa pengakuan atas kesalahan adalah pintu keluar dari kegelapan, dan bahwa taubat suatu kaum dapat menolak azab yang telah tampak.', 'HR Tirmidzi no. 3505 · QS Al-Qalam: 48–50');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('zakaria', 1, 'Pengasuh Maryam di Mihrab', 'Zakaria adalah nabi Bani Israil yang mengasuh Maryam binti Imran. Setiap masuk mihrab, ia mendapati rezeki di sisi Maryam. "Dari mana ini?" tanyanya; Maryam menjawab, "Dari sisi Allah; sesungguhnya Allah memberi rezeki kepada siapa yang Dia kehendaki tanpa hisab." Di tempat itulah tumbuh harapannya yang lama terpendam.', 'QS Ali ''Imran: 37');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('zakaria', 2, 'Doa Lirih di Usia Renta', 'Ia menyeru Tuhannya dengan suara lembut: "Ya Tuhanku, sesungguhnya tulangku telah lemah, kepalaku telah dipenuhi uban, dan aku belum pernah kecewa dalam berdoa kepada-Mu. Aku khawatir terhadap kerabatku sepeninggalku, sedang istriku mandul; maka anugerahilah aku dari sisi-Mu seorang penerus." Allah menjawab dengan kabar gembira: seorang anak bernama Yahya — nama yang belum pernah Allah berikan sebelumnya. Tandanya: Zakaria tidak dapat berbicara dengan manusia selama tiga malam padahal sehat.', 'QS Maryam: 2–11 · QS Ali ''Imran: 38–41 · QS Al-Anbiya: 89–90');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('zakaria', 3, 'Ibrah Kisah Nabi Zakaria', 'Doa Zakaria adalah madrasah adab bermunajat: lirih, penuh pengakuan kelemahan, mengingat rekam jejak kemurahan Allah, dan tidak pernah menyerah oleh usia dan sebab-sebab lahiriah. Allah memuji keluarganya: "Mereka selalu bersegera dalam kebaikan dan berdoa kepada Kami dengan harap dan cemas."', 'QS Al-Anbiya: 90 · QS Maryam: 4');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('yahya', 1, 'Nama yang Belum Pernah Ada', 'Yahya lahir dari doa ayahnya, Zakaria, di usia senja. Allah sendiri yang menamainya: "Wahai Zakaria, Kami memberimu kabar gembira dengan seorang anak laki-laki bernama Yahya, yang Kami belum pernah menjadikan sebelumnya orang yang senama dengannya." Ia membenarkan kalimat dari Allah (Isa), menjadi panutan, menahan diri dari hawa nafsu, dan seorang nabi dari keturunan orang-orang saleh.', 'QS Maryam: 7 · QS Ali ''Imran: 39');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('yahya', 2, 'Diberi Hikmah Selagi Kanak-Kanak', 'Allah memerintahkan, "Wahai Yahya, ambillah Kitab itu dengan kuat." Dan Kami berikan hikmah kepadanya selagi ia masih kanak-kanak, serta kelembutan hati dan kesucian dari sisi Kami. Ia sangat bertakwa, berbakti kepada kedua orang tuanya, dan bukanlah orang yang sombong lagi durhaka. Para ulama menyebutnya nabi yang zuhud, hidup sederhana, dan wafat syahid dibunuh penguasa zalim karena teguh menegakkan hukum Allah.', 'QS Maryam: 12–14');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('yahya', 3, 'Ibrah Kisah Nabi Yahya', 'Salam Allah menaunginya di tiga stasiun kehidupan: "Kesejahteraan atas dirinya pada hari ia dilahirkan, pada hari ia wafat, dan pada hari ia dibangkitkan hidup kembali." Yahya membuktikan bahwa usia muda bukan penghalang kematangan agama, dan bahwa keteguhan pada kebenaran lebih mahal daripada nyawa.', 'QS Maryam: 15');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('isa', 1, 'Maryam dan Kelahiran Tanpa Ayah', 'Maryam, wanita suci pilihan atas seluruh wanita alam, didatangi Jibril dalam rupa manusia sempurna yang menyampaikan kabar: seorang anak suci, padahal ia tak pernah disentuh laki-laki. "Demikianlah; Allah menciptakan apa yang Dia kehendaki. Apabila Dia menetapkan sesuatu, Dia hanya berkata ''jadilah'', maka jadilah ia." Maryam mengasingkan diri, melahirkan di bawah pohon kurma, dan diperintahkan berpuasa bicara. Ketika kaumnya menuduhnya, ia hanya menunjuk bayinya — dan Isa berbicara dari buaian: "Sesungguhnya aku hamba Allah; Dia memberiku Kitab dan menjadikanku seorang nabi."', 'QS Ali ''Imran: 42–47 · QS Maryam: 16–33');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('isa', 2, 'Mukjizat-Mukjizat dengan Izin Allah', 'Isa diutus kepada Bani Israil membenarkan Taurat dan membawa Injil. Dengan izin Allah ia membuat burung dari tanah lalu meniupnya menjadi hidup, menyembuhkan orang buta sejak lahir dan penderita kusta, menghidupkan orang mati, dan mengabarkan apa yang disimpan orang di rumahnya. Setiap mukjizat Al-Qur''an ikat dengan kalimat "bi-idznillah" — dengan izin Allah — menutup pintu pengultusan.', 'QS Ali ''Imran: 49–51 · QS Al-Ma''idah: 110');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('isa', 3, 'Para Hawari dan Hidangan dari Langit', 'Ketika merasakan keingkaran kaumnya, Isa berseru, "Siapakah penolong-penolongku (dalam menegakkan agama) Allah?" Para hawari menjawab, "Kamilah penolong-penolong agama Allah." Atas permintaan mereka, Allah menurunkan hidangan dari langit sebagai hari raya dan tanda — disertai peringatan keras bagi yang kafir sesudahnya. Sebagian Bani Israil beriman dan sebagian kafir, lalu Allah menguatkan orang-orang beriman.', 'QS Ali ''Imran: 52–53 · QS Al-Ma''idah: 112–115 · QS Ash-Shaff: 14');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('isa', 4, 'Diangkat, Bukan Disalib', 'Orang-orang kafir membuat makar untuk membunuhnya, dan Allah membalas makar itu: "Mereka tidak membunuhnya dan tidak menyalibnya, tetapi diserupakan bagi mereka (orang yang dibunuh) itu." Allah mengangkat Isa kepada-Nya. Al-Qur''an juga menegaskan kedudukannya: Isa adalah hamba Allah dan rasul-Nya, kalimat-Nya yang disampaikan kepada Maryam, dan ruh dari-Nya — bukan tuhan dan bukan anak Tuhan. "Sesungguhnya misal Isa di sisi Allah seperti Adam: Dia menciptakannya dari tanah."', 'QS An-Nisa: 157–158 · QS An-Nisa: 171 · QS Ali ''Imran: 59 · QS Al-Ma''idah: 116–118');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('isa', 5, 'Ibrah Kisah Nabi Isa', 'Kisah Isa menegakkan dua benteng sekaligus: membela kesucian Maryam dari tuduhan, dan membela tauhid dari pengultusan. Umat Islam mencintai Isa sebagai rasul ulul azmi dan menanti turunnya di akhir zaman sebagaimana sabda Nabi ﷺ — tanpa sedikit pun menyembahnya.', 'QS Az-Zukhruf: 57–61 · HR Bukhari no. 3448');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('muhammad', 1, 'Yatim yang Dipelihara Allah', 'Muhammad ﷺ lahir di Makkah pada Tahun Gajah dalam keadaan yatim; ayahnya Abdullah wafat sebelum kelahirannya, ibunya Aminah wafat saat ia enam tahun, lalu kakeknya Abdul Muthalib, hingga ia diasuh pamannya Abu Thalib. Allah mengabadikan pemeliharaan ini: "Bukankah Dia mendapatimu sebagai seorang yatim, lalu Dia melindungimu?" Sejak muda ia digelari Al-Amin — yang terpercaya — dan tidak pernah menyembah berhala.', 'QS Ad-Duha: 6–8 · QS Al-Fil: 1–5');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('muhammad', 2, 'Wahyu Pertama di Gua Hira', 'Pada usia empat puluh tahun, saat menyendiri beribadah di Gua Hira, Jibril datang mendekapnya: "Iqra'' — bacalah dengan nama Tuhanmu yang menciptakan." Beliau pulang gemetar, dan Khadijah menenangkannya dengan kalimat yang mengabadikan akhlaknya: "Demi Allah, Allah tidak akan menghinakanmu selamanya; engkau menyambung silaturahmi, menanggung yang lemah, menghormati tamu, dan menolong setiap urusan kebenaran."', 'QS Al-''Alaq: 1–5 · HR Bukhari no. 3 · QS Al-Muddatstsir: 1–7');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('muhammad', 3, 'Dakwah Makkah: Siksaan dan Keteguhan', 'Tiga belas tahun di Makkah, beliau dan para sahabat menghadapi ejekan, boikot, dan penyiksaan — Bilal ditindih batu, keluarga Yasir disiksa hingga syahid. Ditawari harta dan takhta agar berhenti, beliau menjawab bahwa sekiranya matahari diletakkan di tangan kanannya dan bulan di tangan kirinya, ia tidak akan meninggalkan urusan ini hingga Allah memenangkannya atau ia binasa karenanya. Pada tahun duka, Allah menghiburnya dengan Isra'' Mi''raj: diperjalankan malam hari ke Baitul Maqdis lalu ke langit, dan diwajibkannya salat lima waktu.', 'QS Al-Isra: 1 · QS Al-Hijr: 94–97 · QS Al-Kahfi: 6');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('muhammad', 4, 'Hijrah dan Membangun Madinah', 'Ketika kaum musyrik bersepakat membunuhnya, Allah mengizinkan hijrah. Di Gua Tsur, ketika kaki para pengejar tepat di atas kepala, beliau menenangkan Abu Bakar: "Jangan bersedih, sesungguhnya Allah bersama kita." Di Madinah beliau mempersaudarakan Muhajirin dan Anshar, membangun masjid, dan meletakkan piagam yang menata masyarakat majemuk — negara pertama yang berdiri di atas wahyu.', 'QS At-Taubah: 40 · QS Al-Anfal: 30 · QS Al-Hasyr: 9');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('muhammad', 5, 'Badar hingga Fathu Makkah: Kemenangan yang Pemaaf', 'Di Badar, tiga ratusan mukmin mengalahkan seribu pasukan dengan pertolongan Allah. Ujian silih berganti — Uhud, Khandaq, Hudaibiyah yang disebut Allah "kemenangan yang nyata" — hingga Fathu Makkah: beliau memasuki kota yang dulu mengusirnya dengan kepala tertunduk penuh syukur, lalu berkata kepada kaum yang telah menyiksanya, "Pergilah, kalian semua bebas." Berhala-berhala di sekitar Ka''bah dirobohkan: "Kebenaran telah datang dan yang batil telah lenyap."', 'QS Ali ''Imran: 123 · QS Al-Fath: 1 · QS Al-Isra: 81 · QS An-Nasr: 1–3');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('muhammad', 6, 'Haji Wada'' dan Wafatnya Sang Rasul', 'Pada haji perpisahan di Arafah, turunlah ayat, "Pada hari ini telah Aku sempurnakan untukmu agamamu, telah Aku cukupkan nikmat-Ku kepadamu, dan telah Aku ridhai Islam sebagai agamamu." Beliau berpesan tentang darah, harta, dan kehormatan yang haram dilanggar, tentang hak-hak wanita, dan tentang berpegang kepada Kitabullah. Tak lama kemudian beliau wafat di Madinah dalam usia 63 tahun, dengan pesan terakhir: "Ash-shalah, ash-shalah — jagalah salat — dan hamba sahaya yang kalian miliki."', 'QS Al-Ma''idah: 3 · HR Muslim no. 1218 · HR Abu Dawud no. 5156');
INSERT OR IGNORE INTO kisah_person_section (person_slug, section_order, heading_id, body_id, quran_refs) VALUES ('muhammad', 7, 'Ibrah Kisah Nabi Muhammad ﷺ', 'Beliau adalah penutup para nabi, rahmat bagi seluruh alam, dan teladan terbaik dalam seluruh sisi kehidupan — "Dan sesungguhnya engkau benar-benar berbudi pekerti yang agung." Mencintainya berarti mengikuti sunnahnya: "Katakanlah, jika kamu mencintai Allah, ikutilah aku, niscaya Allah mencintaimu."', 'QS Al-Ahzab: 21 · QS Al-Ahzab: 40 · QS Al-Anbiya: 107 · QS Al-Qalam: 4 · QS Ali ''Imran: 31');
